sql:
SELECT product_code
FROM products
WHERE product_code LIKE 'ABC%';

SELECT product_name
FROM products
WHERE material = 'Steel' AND coating = 'Zinc';

SELECT * FROM products WHERE product_id IN (
    SELECT product_id FROM inventory WHERE inventory_id IN (
        SELECT inventory_id FROM access_logs WHERE user_id = (
            SELECT user_id FROM users WHERE user_name = 'Bob Williams'
        )
    )
);

SELECT p.product_id, p.product_name
FROM products p
JOIN product_suppliers ps ON p.product_id = ps.product_id
WHERE ps.lead_time = (
    SELECT MAX(lead_time) FROM product_suppliers
);

SELECT product_name, unit_price
FROM products
WHERE material = 'Steel' AND unit_price > 100;

external_knowledge:
- "ocean of metals": refers to the materials Steel and Aluminum;
- "realms of Type1 and Type2 crafts": refers to the product types Type1 and Type2;
- "substantial fleet of more than ten ships": refers to a product count greater than 10.

